"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[9667],{3661(t,e,o){o.r(e),o.d(e,{comp:()=>a,data:()=>n});var r=o(641);const d={},a=(0,o(6262).A)(d,[["render",function(t,e){return(0,r.uX)(),(0,r.CE)("div",null,[...e[0]||(e[0]=[(0,r.Fv)('<h1 id="tools" tabindex="-1"><a class="header-anchor" href="#tools"><span>Tools</span></a></h1><p><strong>Auctions → Tools</strong> — <code>?page=wkafw-tools</code></p><p>Bulk operations — CSV import / export / mappings, demo-data seeders, cache flush, db migrations, and one-off maintenance scripts.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-tools-exports.png" alt="Tools → Exports queue — CSV download history with the section navigation: 01 Exports · 02 Imports · 03 Maintenance · 04 GDPR · 05 System Status · 06 Audit Chain"></p><h2 id="tool-sections" tabindex="-1"><a class="header-anchor" href="#tool-sections"><span>Tool sections</span></a></h2><table><thead><tr><th>Section</th><th>Use case</th></tr></thead><tbody><tr><td><strong>CSV Import</strong></td><td>Bulk-create auctions from a spreadsheet</td></tr><tr><td><strong>CSV Export</strong></td><td>Bulk-export auctions / bids / watchers / disputes</td></tr><tr><td><strong>Field Mappings</strong></td><td>Map custom CSV columns to plugin fields</td></tr><tr><td><strong>Demo Data</strong></td><td>Seed sample auctions for testing</td></tr><tr><td><strong>Database</strong></td><td>Run migrations, rebuild indexes, recompute totals</td></tr><tr><td><strong>Cache</strong></td><td>Flush internal caches</td></tr><tr><td><strong>Maintenance</strong></td><td>One-off scripts (regen audit chain, recalc balances)</td></tr></tbody></table><h2 id="csv-import" tabindex="-1"><a class="header-anchor" href="#csv-import"><span>CSV Import</span></a></h2><p>Bulk-create auctions from a CSV.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-tools-imports.png" alt="Tools → Imports — bulk upload from CSV with column-mapping, dry-run and progress reporting"></p><h3 id="required-columns" tabindex="-1"><a class="header-anchor" href="#required-columns"><span>Required columns</span></a></h3><table><thead><tr><th>Column</th><th>Type</th><th>Maps to</th></tr></thead><tbody><tr><td><code>product_title</code></td><td>string</td><td>Linked WC product (created if missing)</td></tr><tr><td><code>start_price</code></td><td>decimal</td><td><code>wkafw_auctions.start_price</code></td></tr><tr><td><code>end_date</code></td><td>datetime</td><td><code>wkafw_auctions.end_date</code></td></tr></tbody></table><h3 id="optional-columns" tabindex="-1"><a class="header-anchor" href="#optional-columns"><span>Optional columns</span></a></h3><table><thead><tr><th>Column</th><th>Type</th><th>Maps to</th></tr></thead><tbody><tr><td><code>product_id</code></td><td>int</td><td>Use existing product</td></tr><tr><td><code>auction_type</code></td><td>string</td><td><code>auction_type</code> (default <code>standard</code>)</td></tr><tr><td><code>reserve_price</code></td><td>decimal</td><td><code>reserve_price</code></td></tr><tr><td><code>buy_now_price</code></td><td>decimal</td><td><code>buy_now_price</code></td></tr><tr><td><code>bid_increment</code></td><td>decimal</td><td><code>bid_increment</code></td></tr><tr><td><code>start_date</code></td><td>datetime</td><td><code>start_date</code> (default now)</td></tr><tr><td><code>item_condition</code></td><td>string</td><td><code>item_condition</code></td></tr><tr><td><code>vendor_id</code></td><td>int</td><td>The vendor user this auction belongs to</td></tr><tr><td><code>category</code></td><td>string</td><td>WC product category</td></tr><tr><td><code>description</code></td><td>text</td><td>Product description</td></tr><tr><td><code>images</code></td><td>URL pipe-list</td><td>Featured + gallery images</td></tr></tbody></table><h3 id="import-flow" tabindex="-1"><a class="header-anchor" href="#import-flow"><span>Import flow</span></a></h3><ol><li><strong>Upload</strong> the CSV</li><li><strong>Preview</strong> — first 10 rows, validation errors flagged</li><li><strong>Map fields</strong> — system auto-detects; override any column</li><li><strong>Dry run</strong> — saves a preview without writing</li><li><strong>Import</strong> — runs through Action Scheduler, batched 50 rows at a time</li></ol><p>A results CSV is emailed when done, with success / failure rows broken out.</p><h3 id="custom-field-mappings" tabindex="-1"><a class="header-anchor" href="#custom-field-mappings"><span>Custom field mappings</span></a></h3><p>For columns the importer doesn&#39;t know about (e.g. <code>consignor_name</code>, <code>lot_provenance</code>), register a mapping:</p><p>The new column appears in the import field-mapper UI.</p><h2 id="csv-export" tabindex="-1"><a class="header-anchor" href="#csv-export"><span>CSV Export</span></a></h2><p>Bulk-export with one click.</p><table><thead><tr><th>Export</th><th>Columns</th></tr></thead><tbody><tr><td><strong>All Auctions</strong></td><td>Every column from <code>wkafw_auctions</code> + product title, vendor, bid count</td></tr><tr><td><strong>Active Only</strong></td><td>Same, filtered to <code>status = active</code></td></tr><tr><td><strong>Sold / Paid</strong></td><td>Auctions + linked order ID + amount</td></tr><tr><td><strong>Bids</strong></td><td>Every bid + user email + IP + UA</td></tr><tr><td><strong>Watchers</strong></td><td>User → auction watch relationships</td></tr><tr><td><strong>Disputes</strong></td><td>All disputes + resolution</td></tr><tr><td><strong>Audit log</strong></td><td>Hash-chain ledger</td></tr><tr><td><strong>Wallet ledger</strong></td><td>All wallet transactions</td></tr><tr><td><strong>Vendor commissions</strong></td><td>Earnings split</td></tr><tr><td><strong>Full data dump</strong></td><td>All tables, ZIP&#39;d CSVs</td></tr></tbody></table><p>Big exports run via Action Scheduler; small ones stream immediately.</p><h2 id="demo-data" tabindex="-1"><a class="header-anchor" href="#demo-data"><span>Demo Data</span></a></h2><p>Seed sample auctions for testing.</p><table><thead><tr><th>Seeder</th><th>Creates</th></tr></thead><tbody><tr><td><strong>5 Standard auctions</strong></td><td>5 auctions, varied end dates, 2 with bids</td></tr><tr><td><strong>Multi-vendor sample</strong></td><td>3 vendors × 2 auctions, with commissions</td></tr><tr><td><strong>Charity event</strong></td><td>1 event + 10 charity lots, donor wall populated</td></tr><tr><td><strong>Penny auction set</strong></td><td>3 penny auctions + bid packs for 5 users</td></tr><tr><td><strong>Full demo store</strong></td><td>All of above + 50 users + bid history</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Demo data is real data</p><p>Seeders write actual rows to your database. Run on staging only — never on a live store. The seeded users and products are tagged so the cleanup tool can remove them later.</p></div><h3 id="cleanup" tabindex="-1"><a class="header-anchor" href="#cleanup"><span>Cleanup</span></a></h3><p><strong>Tools → Demo Data → Clean up</strong> removes every demo row created by the seeders. Safe to run repeatedly.</p><h2 id="database" tabindex="-1"><a class="header-anchor" href="#database"><span>Database</span></a></h2><table><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Re-run migrations</strong></td><td>Re-applies any pending schema changes for the current plugin version</td></tr><tr><td><strong>Rebuild indexes</strong></td><td>Optimises every plugin table for fast lookups</td></tr><tr><td><strong>Recompute totals</strong></td><td>Re-sums bid count, current price and revenue from the underlying ledger</td></tr><tr><td><strong>Verify audit chain</strong></td><td>Walks every audit row and checks hash continuity end-to-end</td></tr><tr><td><strong>Truncate audit log</strong></td><td>Permanent — only after archiving</td></tr><tr><td><strong>Schema integrity check</strong></td><td>Compares your installed schema to the expected definition</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Production safety</p><p>Some database tools take exclusive table locks. Schedule them during a maintenance window, not peak bid hours.</p></div><h2 id="cache" tabindex="-1"><a class="header-anchor" href="#cache"><span>Cache</span></a></h2><p>The plugin caches a few hot reads to keep pages fast:</p><ul><li>Auction lookup by ID (5-minute lifetime)</li><li>Active-auction counts (1-minute lifetime)</li><li>Increment-tier parses (per request)</li><li>Customer wallet balance (per request)</li></ul><table><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Flush all</strong></td><td>Clears every plugin cache</td></tr><tr><td><strong>Flush auction caches</strong></td><td>Just auction lookups</td></tr><tr><td><strong>Flush wallet caches</strong></td><td>Just wallet balances</td></tr><tr><td><strong>Warm caches</strong></td><td>Pre-populate active-auction lookups</td></tr></tbody></table><h2 id="maintenance" tabindex="-1"><a class="header-anchor" href="#maintenance"><span>Maintenance</span></a></h2><p>One-off scripts for edge cases:</p><table><thead><tr><th>Script</th><th>When to run</th></tr></thead><tbody><tr><td><strong>Recalculate vendor balances</strong></td><td>After multi-vendor migration</td></tr><tr><td><strong>Re-link orphan auction-orders</strong></td><td>When an order can&#39;t find its source auction</td></tr><tr><td><strong>Re-create missing audit chain</strong></td><td>After table corruption</td></tr><tr><td><strong>Fix UTC drift</strong></td><td>After server timezone change</td></tr><tr><td><strong>Migrate from legacy v1.x schema</strong></td><td>When upgrading from old plugin</td></tr></tbody></table><p>Each script shows a dry-run preview before applying.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-tools-maintenance.png" alt="Tools → Maintenance — pages, rebuilds, recompute totals and one-off scripts"></p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-tools-system.png" alt="Tools → System Status — environment snapshot, plugin / WordPress / WooCommerce versions, PHP limits and active feature flags"></p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-tools-gdpr.png" alt="Tools → GDPR — export-or-erase by email helper for data-subject requests"></p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-tools-audit-chain.png" alt="Tools → Audit Chain — verify the bid ledger integrity end-to-end"></p><h2 id="logging" tabindex="-1"><a class="header-anchor" href="#logging"><span>Logging</span></a></h2><p>All Tools operations are logged to <code>wkafw_auction_logs</code> (action: <code>tool_run</code>) and to the <a href="/admin-audit-log.html" target="_blank" rel="noopener noreferrer">Audit Log</a>. Track who ran what, when, with what arguments.</p>',46)])])}]]),n=JSON.parse('{"path":"/admin-tools.html","title":"Tools","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Tool sections","slug":"tool-sections","link":"#tool-sections","children":[]},{"level":2,"title":"CSV Import","slug":"csv-import","link":"#csv-import","children":[{"level":3,"title":"Required columns","slug":"required-columns","link":"#required-columns","children":[]},{"level":3,"title":"Optional columns","slug":"optional-columns","link":"#optional-columns","children":[]},{"level":3,"title":"Import flow","slug":"import-flow","link":"#import-flow","children":[]},{"level":3,"title":"Custom field mappings","slug":"custom-field-mappings","link":"#custom-field-mappings","children":[]}]},{"level":2,"title":"CSV Export","slug":"csv-export","link":"#csv-export","children":[]},{"level":2,"title":"Demo Data","slug":"demo-data","link":"#demo-data","children":[{"level":3,"title":"Cleanup","slug":"cleanup","link":"#cleanup","children":[]}]},{"level":2,"title":"Database","slug":"database","link":"#database","children":[]},{"level":2,"title":"Cache","slug":"cache","link":"#cache","children":[]},{"level":2,"title":"Maintenance","slug":"maintenance","link":"#maintenance","children":[]},{"level":2,"title":"Logging","slug":"logging","link":"#logging","children":[]}],"git":{},"filePathRelative":"admin-tools.md"}')}}]);